FROM comment
WHERE anonymous_key_hash = #{anonymousKeyHash}
  AND content_markdown = #{contentMarkdown}
  AND created_at >= #{createdAfter}
  AND deleted_at IS NULL

mapper.insert:
INSERT INTO comment (
    article_id, root_id, parent_id, type, content_markdown, content_html,
    nickname, email_ciphertext, website, anonymous_key_hash, status,
    is_admin_reply, notify_on_reply, ip_hash, user_agent_summary
)
VALUES (
    #{articleId}, #{rootId}, #{parentId}, #{type}, #{contentMarkdown}, #{contentHtml},
    #{nickname}, #{emailCiphertext}, #{website}, #{anonymousKeyHash}, #{status},
    #{adminReply}, #{notifyOnReply}, #{ipHash}, #{userAgentSummary}
)

mapper.select:
SELECT c.id, c.article_id, a.title AS article_title, c.parent_id, c.type, c.content_markdown, c.nickname, c.email_ciphertext, c.website, c.status, c.is_admin_reply AS admin_reply, CONCAT(LEFT(c.ip_hash, 8), '…') AS ip_summary, c.created_at FROM comment c LEFT JOIN article a ON a.id = c.article_id WHERE c.deleted_at IS NULL
AND c.status = #{status}
AND c.type = #{type}
AND (c.nickname LIKE CONCAT('%', #{keyword}, '%') OR c.content_markdown LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY (c.status = 'PENDING') DESC, c.created_at DESC, c.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM comment c WHERE c.deleted_at IS NULL
AND c.status = #{status}
